"use strict";(self.webpackChunkhalt_website=self.webpackChunkhalt_website||[]).push([[18709],{92745:e=>{e.exports=JSON.parse('{"tag":{"label":"digestive","permalink":"/docs/tags/digestive","allTagsPath":"/docs/tags","count":2,"items":[{"id":"guinea-pigs/illnesses-and-conditions/bloat-in-guinea-pigs","title":"Bloat in Guinea Pigs","description":"Bloat, also known as Gastric Dilatation and Volvulus (GDV), is a sudden, life-threatening condition that can affect guinea pigs. It occurs when the stomach fills with gas and, in some cases, twists on itself (volvulus), cutting off blood supply to the stomach and other organs. This is a severe medical emergency that requires immediate veterinary intervention. Understanding the signs and acting quickly can be the difference between life and death.","permalink":"/docs/guinea-pigs/illnesses-and-conditions/bloat-in-guinea-pigs"},{"id":"Rabbits/health-and-wellness/home-health-care-for-your-rabbit","title":"Home Health Care for Your Rabbit","description":"Caring for a rabbit can be a deeply rewarding experience, bringing joy and companionship to your home. These intelligent and social creatures, capable of living up to 12\u201315 years, thrive with proper care and attention [1]. Understanding their unique needs \u2014 from diet to dental health and disease prevention \u2014 is crucial for ensuring a long and happy life for your furry friend. This guide walks you through essential aspects of home health care for your rabbit.","permalink":"/docs/Rabbits/health-and-wellness/home-health-care-for-your-rabbit"}],"unlisted":false}}')}}]);